import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  // ✅ Fetch doctor details (FIXED URL)
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`)
      .then((res) => res.json())
      .then((data) => setDoctor(data))
      .catch((err) => console.error("Error:", err));
  }, [doctor_id]);

  // ✅ Go to confirm page
  const handleNext = () => {
    if (!date || !time) {
      alert("Please select date and time");
      return;
    }

    navigate("/appointment", {
      state: {
        doctor,
        date,
        time,
        doctor_id,
      },
    });
  };

  // ✅ Loading state
  if (!doctor) {
    return <h2 style={{ textAlign: "center" }}>Loading...</h2>;
  }

  return (
    <div style={styles.container}>
      <Navbar />

      <div style={styles.main}>
        <div style={styles.card}>

          {/* Left - Image */}
          <div style={styles.left}>
            <img
              src={
                doctor.image
                  ? `http://127.0.0.1:8000/media/${doctor.image}`
                  : "https://cdn-icons-png.flaticon.com/512/387/387561.png"
              }
              alt="doctor"
              style={styles.image}
            />
          </div>

          {/* Right - Details */}
          <div style={styles.right}>
            <h2>{doctor.name}</h2>
            <p><strong>Specialization:</strong> {doctor.field}</p>
            <p><strong>Experience:</strong> {doctor.experience || "N/A"}</p>
            <p><strong>Qualification:</strong> {doctor.qualification || "N/A"}</p>

            <p style={styles.about}>
              <strong>About:</strong> {doctor.about || "No details available"}
            </p>

            {/* Booking Section */}
            <div style={styles.bookingSection}>
              <label>Select Date:</label>
              <input
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                style={styles.input}
              />

              <label>Select Time:</label>
              <select
                value={time}
                onChange={(e) => setTime(e.target.value)}
                style={styles.input}
              >
                <option value="">Select Time</option>
                <option value="10:00 AM">10:00 AM</option>
                <option value="11:00 AM">11:00 AM</option>
                <option value="02:00 PM">02:00 PM</option>
                <option value="04:00 PM">04:00 PM</option>
              </select>

              <button style={styles.button} onClick={handleNext}>
                Book Appointment
              </button>
            </div>
          </div>

        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    minHeight: "100vh",
    backgroundColor: "#f4f6f9",
    fontFamily: "Arial, sans-serif",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
  },

  card: {
    display: "flex",
    backgroundColor: "white",
    borderRadius: "10px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
    padding: "30px",
    width: "700px",
    gap: "30px",
  },

  left: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },

  image: {
    width: "150px",
    height: "150px",
    borderRadius: "50%",
  },

  right: {
    flex: 1,
  },

  about: {
    marginTop: "10px",
  },

  bookingSection: {
    marginTop: "20px",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },

  input: {
    padding: "8px",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },

  button: {
    marginTop: "10px",
    padding: "10px",
    backgroundColor: "#2c3e50",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
};
